diagram.d2:
direction: right
ev: { label: "sim events\ngoals · trades · firings"; class: external }
obs: { label: "StatObserver"; class: actor }
tags: { label: "TagLayer"; class: store }
dir: { label: "Director\nspawn · beat · resolve"; class: changed }
mem: { label: "NarrativeMemory"; class: store }
out: { label: "News · Prose" }
ev -> obs: observe
obs -> tags: emit tags
tags -> dir: poll
dir -> mem: write memory
dir -> out: surface

diagrams.d2:
direction: right
game: { label: "recordGame\n5/10/25-game windows"; class: actor }
pred: { label: "predicates\nslump · hot streak" }
buf: { label: "buffered emits" }
flush: { label: "flushTick → TagLayer"; class: changed }
game -> pred
pred -> buf: fire
buf -> flush: day boundary

direction: right
ev: { label: "narrative moment"; class: actor }
log: { label: "KMEvent\n~150 B · always logged"; class: store }
sal: { label: "isSalient?" }
rich: { label: "NarrativeMemoryEntry\n~500-1100 B · on Person/Franchise"; class: changed }
ev -> log: append
ev -> sal
sal -> rich: if salient

diagrams.mermaid:
flowchart LR
  ev["narrative moment"] --> log["KMEvent: ~150 B always logged"]
  ev --> sal{"isSalient?"}
  sal -->|if salient| rich["NarrativeMemoryEntry: on Person/Franchise"]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  classDef store fill:#e5dbff,stroke:#9775fa,color:#1b1b1b;
  class ev actor; class log store; class rich changed;

diagrams.d2:
direction: right
tick: { label: "dailyTick(now)"; class: actor }
exp: { label: "expire tags\n+ beef decay" }
flush: { label: "observer.flushTick\nemit buffered tags" }
vig: { label: "rollDailyVignettes" }
dir: { label: "directorTick"; class: changed }
news: { label: "news sampler" }
tick -> exp
exp -> flush
flush -> vig
vig -> dir
dir -> news

diagrams.mermaid:
flowchart LR
  tick["dailyTick(now)"] --> exp["expire tags + beef decay"]
  exp --> flush["observer.flushTick: emit tags"]
  flush --> vig["rollDailyVignettes"]
  vig --> dir["directorTick"]
  dir --> news["news sampler"]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  class tick actor; class dir changed;

diagrams.d2:
direction: right
seed: { label: "ArcSeed\nmutation-driven"; class: actor }
poll: { label: "template poll\neligibility + weight" }
cast: { label: "castTemplate\nfill roles from candidates"; class: changed }
beat: { label: "fireBeat\neffects + flavor" }
res: { label: "resolve\n→ arcHistory" }
seed -> poll
poll -> cast: weighted pick
cast -> beat: trigger fires
beat -> beat: next beat
beat -> res: resolution matches

diagrams.mermaid:
flowchart LR
  seed["ArcSeed: mutation-driven"] --> poll["template poll: eligibility + weight"]
  poll -->|weighted pick| cast["castTemplate: fill roles"]
  cast -->|trigger fires| beat["fireBeat: effects + flavor"]
  beat -->|next beat| beat
  beat -->|resolution matches| res["resolve to arcHistory"]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  class seed actor; class cast changed;
